const inputItem = $input.first();
const payload = inputItem.json?.body ?? [];
const entries = Array.isArray(payload) ? payload : [payload];

const blockedTypes = new Set(["SOA", "IXFR"]);
const blockedClientIps = new Set([
  "172.22.16.1",
  "172.21.16.1",
]);

function formatRfc3164Utc(ts) {
  const hasExplicitTimestamp =
    ts !== null &&
    ts !== undefined &&
    String(ts).trim() !== "";

  const date = hasExplicitTimestamp ? new Date(ts) : new Date();

  if (Number.isNaN(date.getTime())) {
    return null;
  }

  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun",
                  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

  const mon = months[date.getUTCMonth()];
  const day = date.getUTCDate();
  const dd = day < 10 ? ` ${day}` : `${day}`;
  const hh = String(date.getUTCHours()).padStart(2, "0");
  const mm = String(date.getUTCMinutes()).padStart(2, "0");
  const ss = String(date.getUTCSeconds()).padStart(2, "0");

  return `${mon} ${dd} ${hh}:${mm}:${ss}`;
}

function tryParseJsonString(value) {
  if (typeof value !== "string" || !value.trim()) return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}

function normalizeClientIp(value) {
  const raw = String(value ?? "").trim();
  if (!raw) return "";

  const bracketedIpv6 = raw.match(/^\[([0-9a-fA-F:.]+)\](?::\d+)?$/);
  if (bracketedIpv6) return bracketedIpv6[1];

  const ipv4WithPort = raw.match(/^((?:\d{1,3}\.){3}\d{1,3})(?::\d+)?$/);
  if (ipv4WithPort) return ipv4WithPort[1];

  return raw;
}

const out = [];

for (const entry of entries) {
  const parsed =
    tryParseJsonString(entry?.RenderedMessage) ??
    tryParseJsonString(entry?.MessageTemplate) ??
    (entry && typeof entry === "object" ? entry : null);

  if (!parsed || typeof parsed !== "object") {
    out.push({
      json: {
        ok: true,
        forwarded: false,
        skipReason: "unparsable_log_entry",
        original: entry,
      },
    });
    continue;
  }

  const timestampRaw =
    parsed.timestamp ??
    parsed.Timestamp ??
    entry?.Timestamp ??
    null;

  const clientIpRaw =
    parsed.clientIp ??
    parsed.clientIPAddress ??
    parsed.client ??
    parsed.remoteAddress ??
    null;

  const question = parsed.question ?? {};
  const questionName =
    question.questionName ??
    question.name ??
    parsed.questionName ??
    parsed.domain ??
    null;

  const questionType =
    question.questionType ??
    question.type ??
    parsed.questionType ??
    parsed.type ??
    null;

  const protocolRaw = String(parsed.protocol ?? "").trim();
  const responseCodeRaw = String(parsed.responseCode ?? "").trim();
  const responseTypeRaw = String(parsed.responseType ?? "").trim();

  const normalizedType = String(questionType ?? "").trim().toUpperCase();
  const normalizedName = String(questionName ?? "").trim();
  const normalizedClientIp = normalizeClientIp(clientIpRaw);

  let skipReason = null;

  if (!normalizedType) {
    skipReason = "missing_question_type";
  } else if (!normalizedName) {
    skipReason = "missing_question_name";
  } else if (!normalizedClientIp) {
    skipReason = "missing_client_ip";
  } else if (blockedTypes.has(normalizedType)) {
    skipReason = `filtered_type_${normalizedType}`;
  } else if (blockedClientIps.has(normalizedClientIp)) {
    skipReason = `filtered_client_${normalizedClientIp}`;
  }

  if (skipReason) {
    out.push({
      json: {
        ok: true,
        forwarded: false,
        skipReason,
        original: parsed,
        originalEntry: entry,
      },
    });
    continue;
  }

  const rfc3164Timestamp = formatRfc3164Utc(timestampRaw);

  if (!rfc3164Timestamp) {
    out.push({
      json: {
        ok: true,
        forwarded: false,
        skipReason: "invalid_timestamp",
        parsed: {
          timestampRaw,
          clientIp: normalizedClientIp,
          questionName: normalizedName,
          questionType: normalizedType,
          protocol: protocolRaw || null,
          responseCode: responseCodeRaw || null,
          responseType: responseTypeRaw || null,
        },
        original: parsed,
        originalEntry: entry,
      },
    });
    continue;
  }

  const extras = [
    protocolRaw ? `proto=${protocolRaw}` : null,
    responseCodeRaw ? `rcode=${responseCodeRaw}` : null,
    responseTypeRaw ? `rtype=${responseTypeRaw}` : null,
  ].filter(Boolean).join(" ");

  const syslogLine =
    `<14>${rfc3164Timestamp} technitium-dns dnsmasq[1]: ` +
    `query[${normalizedType}] ${normalizedName} from ${normalizedClientIp}` +
    (extras ? ` ${extras}` : "");

  out.push({
    json: {
      ok: true,
      forwarded: true,
      skipReason: null,
      syslogLine,
      parsed: {
        timestampRaw,
        clientIp: normalizedClientIp,
        questionName: normalizedName,
        questionType: normalizedType,
        protocol: protocolRaw || null,
        responseCode: responseCodeRaw || null,
        responseType: responseTypeRaw || null,
      },
      original: parsed,
      originalEntry: entry,
    },
  });
}

return out;
